+
+  // Updated in each on_update() call
+  Eigen::Isometry3d _pose;
+  double _sim_time = 0.0;
+
+  rclcpp::Publisher<rmf_fleet_msgs::msg::RobotState>::SharedPtr _robot_state_pub;
